            ),
          ),
          const SizedBox(height: 12),
          _SummaryRow(
            icon: Icons.photo_size_select_large,
            label: l10n.exportResolution,
            value: resolutionText,
          ),
          const SizedBox(height: 8),
          _SummaryRow(
            icon: Icons.image,
